function setThemeCss(themeData) {
        var DEFAULT_BG_VALUE = 'texture';

        themeData = themeData || {};
        var colors = themeData.colors && Array.isArray(themeData.colors) ? themeData.colors : ["#34302E", "#312D2A", DEFAULT_BG_VALUE];//the redwood colors by default
        var isCustomTheme = themeData.isCustom;
        var themeLabel = themeData.label;
        var darkness = themeData.darkness && Array.isArray(themeData.darkness) ? themeData.darkness : [1, 1, 0];//the redwood colors by default
        var bgColorIsSet = colors && colors[2] && colors[2] !== DEFAULT_BG_VALUE;
        //set CSS variables vith theme colors
        document.documentElement.style.setProperty('--theme-header-background-color', colors && colors[0] || "#34302E");
        document.documentElement.style.setProperty('--theme-button-background-color', colors && colors[1] || "#312D2A");
        if (bgColorIsSet) {
            document.documentElement.style.setProperty('--theme-page-background-color', colors[2]);
        } else {
            document.documentElement.style.setProperty('--theme-page-background-color', 'transparent');
        }

        //remove all "theme******" CSS classes
        document.body.classList.forEach(function(className){
            if (className.indexOf('theme') !== -1) {
                document.body.classList.remove(className);
            }
        });

        document.body.classList.add('themeredwood'); //TODO It is a mistake "themeredwood" shouldn't be added with "custom-theme" but it is legacy!!!

        //add custom theme class
        if (isCustomTheme) {
            document.body.classList.add(themeLabel);
            document.body.classList.add('custom-theme');
        }

        //update classes that is responsible for darkness
        [
            'dark-header',
            'dark-page',
            'dark-submit',
            'light-header',
            'light-page',
            'light-submit',
            'bg-color-set'
        ].forEach(function (className) {
            document.body.classList.remove(className);
        });

        if (darkness[0]) {
            document.body.classList.add('dark-header');
        } else {
            document.body.classList.add('light-header');
        }

        if (darkness[1]) {
            document.body.classList.add('dark-submit');
        } else {
            document.body.classList.add('light-submit');
        }

        if (darkness[2]) {
            document.body.classList.add('dark-page');
        } else {
            document.body.classList.add('light-page');
        }
        bgColorIsSet && document.body.classList.add('bg-color-set');
    }

    try {
        setThemeCss({"darkness":[1,1,0],"colors":["#34302E","#312D2A","texture"],"isCustom":0,"label":"themeredwood","text":"Field Service"});
    } catch (e){
        console.error(e);
    }

body.self-heal-checking {
        font-family: 'Oracle Sans', sans-serif;
        font-size: 1rem;
        background-color: rgb(252, 251, 250);
    }
    #wait {
        display: flex;
        align-content: center;
        align-items: center;
        justify-content: center;
        text-align: center;
        left: 50%;
        top: 50%;
        transform: translate(-50%, -50%);
        z-index: 1;
        position: fixed;
    }
    #wait .text-message {
        font-size   : 1.375rem;
        font-family : Arial, Helvetica, Roboto, sans-serif !important;
        font-stretch: condensed;
        font-weight : 300 !important;
        text-align  : center;
        line-height : 1.5rem;
        margin-top  : 18px;
        color       : rgba(22, 21, 19, 0.65);
    }
    #wait_text {
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
    }
    #wait .loading-animated-icon {
        display: inline-block;
    }

    .user-confirm {
        position: absolute;
        z-index: 2;
        left: 0;
        right: 0;
        top: 0;
        bottom: 0;
        overflow: auto;
        min-width: 320px;
        background: #306170 url('../r2601.280.26.04.40544/mobile/css/../images/themeredwood/jpeg/Abstracts_Blue_2.jpg') center center no-repeat;
        background-size: cover;
        font-family: 'Oracle Sans';
        color: #fcfbfa;
        display: -webkit-box;
        display: -ms-flexbox;
        display: flex;
        -webkit-box-align: start;
        -ms-flex-align: start;
        align-items: start;
        -webkit-box-pack: center;
        -ms-flex-pack: center;
        justify-content: center;
    }
    .user-confirm-content {
        -webkit-box-orient: vertical;
        -webkit-box-direction: normal;
        -ms-flex-direction: column;
        flex-direction: column;
        width: 300px;
        margin: 215px 0 40px 0;
    }
    .user-confirm-header {
        font-size: 20px;
        font-weight: bold;
    }
    .user-confirm-text {
        margin: 32px 0px 8px;
        font-size: 14px;
        font-weight: normal;
    }
    .user-confirm-button {
        font-family: 'Oracle Sans';
        font-weight: 500;
        font-size: 14px;
        border: 1px solid #A1a09F;
        border-radius: 4px;
        color: #1A1816;
        background: #FFF;
        box-sizing: border-box;
        padding: 8px 16px;
        height: 36px;
        min-width: 88px;
    }
    .user-confirm-button:hover, .user-confirm-button:focus {
        background-color: rgba(22, 21, 19, 0.04);
        border-color: rgba(22, 21, 19, 0.6);
    }
    .user-confirm-button:focus {
        border-color: rgba(22, 21, 19, 0.6);
        outline: 1px dotted #161513;
        outline-offset: 1px;
    }
    .user-confirm-button:disabled {
        border-color: transparent;
        color: rgba(22, 21, 19, 0.3);
        background: rgba(123, 117, 112, 0.1);
        box-shadow: none;
    }
    .user-confirm-button.submit {
        color: #FFFFFF;
        background: rgb(67, 107, 29);
        border: none;
    }
    .user-confirm-button.submit:hover {
        background-color: #577346;
        background-image: linear-gradient(rgba(255, 255, 255, 0.15), rgba(255, 255, 255, 0.15));
        border-color: transparent;
    }
    .user-confirm-button.submit:active {
        background-color: #4F693F;
    }
    .user-confirm-button.submit:disabled {
        background-color: #FCFBFA;
        color: #D2D0CF;
    }
    .user-confirm-button.submit:focus {
        background-color: #4F693F;
        outline: 1px dotted #161513;
        outline-offset: 1px;
    }
    .user-confirm-button:focus:not(:disabled) {
        box-shadow: none;
    }

    .loading-animated-icon {
        width: 32px;
        height: 32px;
        overflow: hidden;
        position: relative;
    }
    .loading-animated-icon .part1 {
        display: block;
        position: absolute;
        top: 0;
        left: 0;
        width: 15px;
        height: 15px;
        border-top-left-radius: 32px;
        border: 1px solid #777;
        border-bottom: 0 none;
        border-right: 0 none;
        -webkit-transform-origin: 16px 16px;
        transform-origin: 16px 16px;
        -webkit-animation: loading-animated-icon-rotating 1.2s linear infinite;
        animation: loading-animated-icon-rotating 1.2s linear infinite;
    }
    .loading-animated-icon .part2 {
        display: block;
        position: absolute;
        bottom: 4px;
        right: 4px;
        width: 11px;
        height: 11px;
        border-bottom-right-radius: 32px;
        border: 1px solid #777;
        border-top: 0 none;
        border-left: 0 none;
        -webkit-transform-origin: left top;
        transform-origin: left top;
        -webkit-animation: loading-animated-icon-rotating-backwards 1s linear infinite;
        animation: loading-animated-icon-rotating-backwards 1s linear infinite;
    }
    .loading-animated-icon.none-animation-default .part1 {
        -webkit-animation: none;
        animation: none;
    }
    .loading-animated-icon.none-animation-default .part2 {
        -webkit-animation: none;
        animation: none;
    }
    .loading-animated-icon.none-animation-default.start-animation .part1 {
        -webkit-animation: loading-animated-icon-rotating 0.7s linear infinite;
        animation: loading-animated-icon-rotating 0.7s linear infinite;
    }
    .loading-animated-icon.none-animation-default.start-animation .part2 {
        -webkit-animation: loading-animated-icon-rotating-backwards 0.5s linear infinite;
        animation: loading-animated-icon-rotating-backwards 0.5s linear infinite;
    }
    .loading-animated-icon.loading-start .part1 {
        border-color: #777;
    }
    .loading-animated-icon.loading-start .part2 {
        border-color: #777;
    }
    .loading-animated-icon.loading-wait .part1 {
        border-color: #777;
    }
    .loading-animated-icon.loading-wait .part2 {
        border-color: #777;
    }
    .loading-animated-icon.big {
        width: 64px;
        height: 64px;
    }
    .loading-animated-icon.big .part1 {
        width: 31px;
        height: 31px;
        border-top-left-radius: 64px;
        border-width: 1px;
        -webkit-transform-origin: 32px 32px;
        transform-origin: 32px 32px;
    }
    .loading-animated-icon.big .part2 {
        bottom: 4px;
        right: 4px;
        width: 27px;
        height: 27px;
        border-bottom-right-radius: 64px;
        border-width: 1px;
    }

    @-webkit-keyframes loading-animated-icon-rotating {
        100% {
            -webkit-transform: rotate(360deg);
            transform: rotate(360deg);
        }
    }
    @-webkit-keyframes loading-animated-icon-rotating-backwards {
        100% {
            -webkit-transform: rotate(-360deg);
            transform: rotate(-360deg);
        }
    }
    @keyframes loading-animated-icon-rotating {
        100% {
            -webkit-transform: rotate(360deg);
            transform: rotate(360deg);
        }
    }
    @keyframes loading-animated-icon-rotating-backwards {
        100% {
            -webkit-transform: rotate(-360deg);
            transform: rotate(-360deg);
        }
    }

    .hidden {
        display: none;
    }
